class Solution {
public:
    bool isFascinating(int n) {
        int two_n = 2 * n;
        int three_n = 3 * n;

        if (two_n < 100 || two_n > 999 || three_n < 100 || three_n > 999) {
            return false;
        }

        string s = to_string(n) + to_string(two_n) + to_string(three_n);

        if (s.size() != 9) {
            return false;
        }

        bool digits[10] = {false};

        for (char c : s) {
            int d = c - '0';
            if (d == 0) {
                return false;
            }
            if (digits[d]) {
                return false;
            }
            digits[d] = true;
        }

        return true;
    }
};

